// Define a function to extract heading tags from a string
function extractHeadingTags(input) {
	let tags = input.match(/<h\d+>[^<]*</h\d+/g);
	return tags.join('');
}

solutions.python:
import re

def extract_heading_tags(input_str):
	tags = re.findall(r'<h\d+>[^<]*</h\d+>', input_str);
	return ''.join(tags);
